 1→import { and, desc, eq, sql } from "drizzle-orm";
 2→import { db } from "../db";
 3→import { jobMatches } from "../db/schema";
 4→
 5→// ========== Types ==========
 6→
 7→export type Match = typeof jobMatches.$inferSelect;
 8→
 9→export type ListMatchesOptions = {
10→  jobId?: string;
11→  candidateId?: string;
12→  status?: string;
13→  limit?: number;
14→  offset?: number;
15→};
16→
17→export type CreateMatchData = {
18→  jobId: string;
19→  candidateId: string;
20→  matchScore: number;
21→  confidence?: number;
22→  reasoning?: string;
23→  model?: string;
24→  criteriaBreakdown?: unknown;
25→  riskProfile?: unknown;
26→  enrichmentSuggestions?: unknown;
27→  recommendation?: string;
28→  recommendationConfidence?: number;
29→  assessmentModel?: string;
30→};
31→
32→// ========== Service Functions ==========
33→
34→/** Matches ophalen met optionele filters. Geordend op matchScore aflopend. */
35→export async function listMatches(opts: ListMatchesOptions = {}): Promise<Match[]> {
36→  const limit = Math.min(opts.limit ?? 50, 100);
37→  const offset = Math.max(0, opts.offset ?? 0);
38→
39→  const conditions: ReturnType<typeof eq>[] = [];
40→
41→  if (opts.jobId) {
42→    conditions.push(eq(jobMatches.jobId, opts.jobId));
43→  }
44→
45→  if (opts.candidateId) {
46→    conditions.push(eq(jobMatches.candidateId, opts.candidateId));
47→  }
48→
49→  if (opts.status) {
50→    conditions.push(eq(jobMatches.status, opts.status));
51→  }
52→
53→  return db
54→    .select()
55→    .from(jobMatches)
56→    .where(and(...conditions))
57→    .orderBy(desc(jobMatches.matchScore))
58→    .limit(limit)
59→    .offset(offset);
60→}
61→
62→export async function countMatches(
63→  opts: Omit<ListMatchesOptions, "limit" | "offset"> = {},
64→): Promise<number> {
65→  const conditions: ReturnType<typeof eq>[] = [];
66→  if (opts.jobId) conditions.push(eq(jobMatches.jobId, opts.jobId));
67→  if (opts.candidateId) conditions.push(eq(jobMatches.candidateId, opts.candidateId));
68→  if (opts.status) conditions.push(eq(jobMatches.status, opts.status));
69→
70→  const [{ count }] = await db
71→    .select({ count: sql<number>`count(*)::int` })
72→    .from(jobMatches)
73→    .where(and(...conditions));
74→  return count ?? 0;
75→}
76→
77→/** Enkele match ophalen op ID, of null als niet gevonden. */
78→export async function getMatchById(id: string): Promise<Match | null> {
79→  const rows = await db.select().from(jobMatches).where(eq(jobMatches.id, id)).limit(1);
80→

