 1→import { convertToModelMessages, stepCountIs } from "ai";
 2→
 3→import { z } from "zod";
 4→import { buildSystemPrompt, chatModel, recruitmentTools } from "@/src/ai/agent";
 5→import { db } from "@/src/db";
 6→import { chatSessions } from "@/src/db/schema";
 7→import { tracedStreamText as streamText } from "@/src/lib/ai-models";
 8→import { rateLimit } from "@/src/lib/rate-limit";
 9→
10→const limiter = rateLimit({ interval: 60_000, limit: 20 });
11→const MAX_STORED_MESSAGES = 50;
12→
13→const contextSchema = z
14→  .object({
15→    route: z.string().max(200).nullish(),
16→    entityId: z.string().uuid().nullish(),
17→    entityType: z.enum(["opdracht", "kandidaat"]).nullish(),
18→    sessionId: z.string().max(100).nullish(),
19→  })
20→  .nullish();
21→
22→export async function POST(req: Request) {
23→  const ip =
24→    req.headers.get("x-real-ip") ??
25→    req.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
26→    "anonymous";
27→  const { success, reset } = limiter.check(ip);
28→  if (!success) {
29→    return Response.json(
30→      { error: "Te veel verzoeken. Probeer het later opnieuw." },
31→      { status: 429, headers: { "Retry-After": String(Math.ceil((reset - Date.now()) / 1000)) } },
32→    );
33→  }
34→
35→  const body = await req.json().catch(() => null);
36→  if (!body || !Array.isArray(body.messages)) {
37→    return Response.json({ error: "Ongeldige aanvraag" }, { status: 400 });
38→  }
39→
40→  const contextResult = contextSchema.safeParse(body.context);
41→  if (!contextResult.success) {
42→    return Response.json({ error: "Ongeldige context" }, { status: 400 });
43→  }
44→
45→  const ctx = contextResult.data ?? undefined;
46→  const sessionId = ctx?.sessionId;
47→
48→  // Persist conversation turn (fire-and-forget, non-blocking)
49→  if (sessionId) {
50→    const lastMessages = body.messages.slice(-MAX_STORED_MESSAGES);
51→    db.insert(chatSessions)
52→      .values({
53→        sessionId,
54→        messages: lastMessages,
55→        context: ctx,
56→        messageCount: lastMessages.length,
57→      })
58→      .onConflictDoUpdate({
59→        target: chatSessions.sessionId,
60→        set: {
61→          messages: lastMessages,
62→          context: ctx,
63→          messageCount: lastMessages.length,
64→          updatedAt: new Date(),
65→        },
66→      })
67→      .catch(() => {}); // Non-blocking — don't fail the chat if persistence fails
68→  }
69→
70→  const system = await buildSystemPrompt(ctx);
71→
72→  const result = streamText({
73→    model: chatModel,
74→    system,
75→    messages: await convertToModelMessages(body.messages),
76→    tools: recruitmentTools,
77→    stopWhen: stepCountIs(5),
78→  });
79→
80→  return result.toUIMessageStreamResponse({
81→    sendReasoning: true,
82→    sendSources: true,
83→  });
84→}
