 39→  const fileInputRef = useRef<HTMLInputElement>(null);
 40→
 41→  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
 42→    const file = e.target.files?.[0];
 43→    if (!file) return;
 44→
 45→    if (!ALLOWED_CV_TYPES.includes(file.type)) {
 46→      setError("Alleen PDF en Word (.docx) bestanden zijn toegestaan.");
 47→      return;
 48→    }
 49→    if (file.size > MAX_CV_SIZE_MB * 1024 * 1024) {
 50→      setError(`Bestand te groot. Maximaal ${MAX_CV_SIZE_MB}MB.`);
 51→      return;
 52→    }
 53→
 54→    setError("");
 55→    setCvFile(file);
 56→  };
 57→
 58→  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
 59→    e.preventDefault();
 60→    setLoading(true);
 61→    setError("");
 62→
 63→    const form = e.currentTarget;
 64→    const data = new FormData(form);
 65→
 66→    const name = data.get("name") as string;
 67→    if (!name.trim()) {
 68→      setError("Naam is verplicht.");
 69→      setLoading(false);
 70→      return;
 71→    }
 72→
 73→    const payload: Record<string, unknown> = {
 74→      name: name.trim(),
 75→      source: "manual",
 76→    };
 77→
 78→    const email = (data.get("email") as string)?.trim();
