 87→    const location = (data.get("location") as string)?.trim();
 88→    if (location) payload.location = location;
 89→
 90→    const hourlyRate = (data.get("hourlyRate") as string)?.trim();
 91→    if (hourlyRate) payload.hourlyRate = Number.parseInt(hourlyRate, 10);
 92→
 93→    const availability = (data.get("availability") as string)?.trim();
 94→    if (availability) payload.availability = availability;
 95→
 96→    const linkedinUrl = (data.get("linkedinUrl") as string)?.trim();
 97→    if (linkedinUrl) payload.linkedinUrl = linkedinUrl;
 98→
 99→    const notes = (data.get("notes") as string)?.trim();
100→    if (notes) payload.notes = notes;
101→
102→    try {
103→      // Phase 1: Create candidate
104→      setLoadingMessage("Kandidaat aanmaken...");
105→      const res = await fetch("/api/kandidaten", {
106→        method: "POST",
107→        headers: { "Content-Type": "application/json" },
108→        body: JSON.stringify(payload),
109→      });
110→
111→      if (!res.ok) {
