181→          </div>
182→
183→          {/* Email + Telefoon row */}
184→          <div className="grid grid-cols-2 gap-3">
185→            <div className="space-y-1.5">
186→              <label htmlFor="ac-email" className="text-sm font-medium text-foreground">
187→                E-mail
188→              </label>
189→              <Input id="ac-email" name="email" type="email" placeholder="naam@voorbeeld.nl" />
190→            </div>
191→            <div className="space-y-1.5">
192→              <label htmlFor="ac-phone" className="text-sm font-medium text-foreground">
193→                Telefoon
194→              </label>
195→              <Input id="ac-phone" name="phone" type="tel" placeholder="+31 6 ..." />
