### Step 6: Create the client form component

**File:** `/Users/cortex-air/Developer/motian/components/settings-form.tsx` (new file)

```typescript
"use client";

import { CheckCircle, Loader2, Settings, Shield, Bell } from "lucide-react";
import { useRouter } from "next/navigation";
