 1→import { desc, eq, sql } from "drizzle-orm";
 2→import { db } from "../db";
 3→import { jobs, scrapeResults } from "../db/schema";
 4→
 5→// ========== Types ==========
 6→
 7→export type ScrapeResult = typeof scrapeResults.$inferSelect;
 8→
 9→export type GetHistoryOptions = {
10→  platform?: string;
11→  limit?: number;
12→};
13→
14→export type PlatformStats = {
15→  platform: string;
16→  totalRuns: number;
17→  successCount: number;
18→  failedCount: number;
19→  successRate: number;
20→  totalJobsFound: number;
21→  totalJobsNew: number;
22→  totalDuplicates: number;
23→  avgDurationMs: number;
24→};
25→
26→export type ScrapeAnalytics = {
27→  totalRuns: number;
28→  totalJobsFound: number;
29→  totalJobsNew: number;
30→  totalDuplicates: number;
31→  totalUniqueJobs: number;
32→  overallSuccessRate: number;
33→  avgDurationMs: number;
34→  byPlatform: PlatformStats[];
35→};
36→
37→// ========== Service Functions ==========
38→
39→/** Scrape resultaten ophalen, optioneel gefilterd op platform en gelimiteerd */
40→export async function getHistory(opts: GetHistoryOptions = {}): Promise<ScrapeResult[]> {
41→  const limit = Math.min(opts.limit ?? 50, 100);
42→
43→  const baseQuery = db.select().from(scrapeResults);
44→  const filtered = opts.platform
45→    ? baseQuery.where(eq(scrapeResults.platform, opts.platform))
46→    : baseQuery;
47→
48→  return filtered.orderBy(desc(scrapeResults.runAt)).limit(limit);
49→}
50→
51→/** Bereken analytics per platform over alle scrape resultaten */
52→export async function getAnalytics(): Promise<ScrapeAnalytics> {
53→  // Single query: platform aggregation + unique jobs count via subquery
54→  const rows = await db
55→    .select({
56→      platform: scrapeResults.platform,
57→      totalRuns: sql<number>`count(*)::int`,
58→      successCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'success')::int`,
59→      failedCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'failed')::int`,
60→      totalJobsFound: sql<number>`coalesce(sum(${scrapeResults.jobsFound}), 0)::int`,
61→      totalJobsNew: sql<number>`coalesce(sum(${scrapeResults.jobsNew}), 0)::int`,
62→      totalDuplicates: sql<number>`coalesce(sum(${scrapeResults.duplicates}), 0)::int`,
63→      avgDurationMs: sql<number>`coalesce(avg(${scrapeResults.durationMs}), 0)::int`,
64→      totalUniqueJobs: sql<number>`(select count(*)::int from ${jobs} where ${jobs.deletedAt} is null)`,
65→    })
66→    .from(scrapeResults)
67→    .groupBy(scrapeResults.platform);
68→
69→  // Extract unique jobs count from first row (subquery returns same value for all rows)
70→  const totalUniqueJobs = rows[0]?.totalUniqueJobs ?? 0;
71→
72→  const byPlatform: PlatformStats[] = rows.map(({ totalUniqueJobs: _, ...r }) => ({
73→    ...r,
74→    successRate: r.totalRuns > 0 ? Math.round((r.successCount / r.totalRuns) * 100) : 0,
75→  }));
76→
77→  const totalRuns = byPlatform.reduce((s, p) => s + p.totalRuns, 0);
78→  const totalSuccess = byPlatform.reduce((s, p) => s + p.successCount, 0);
79→
80→  return {
81→    totalRuns,
82→    totalJobsFound: byPlatform.reduce((s, p) => s + p.totalJobsFound, 0),
83→    totalJobsNew: byPlatform.reduce((s, p) => s + p.totalJobsNew, 0),
84→    totalDuplicates: byPlatform.reduce((s, p) => s + p.totalDuplicates, 0),
85→    totalUniqueJobs,
86→    overallSuccessRate: totalRuns > 0 ? Math.round((totalSuccess / totalRuns) * 100) : 0,
87→    avgDurationMs:
88→      byPlatform.length > 0
89→        ? Math.round(byPlatform.reduce((s, p) => s + p.avgDurationMs, 0) / byPlatform.length)
90→        : 0,
91→    byPlatform,
92→  };
93→}
