10→
11→const limiter = rateLimit({ interval: 300_000, limit: 5 });
12→
13→export const dynamic = "force-dynamic";
14→
15→const triggerSchema = z.object({
16→  platform: z.string().optional(),
17→});
18→
19→export async function POST(request: NextRequest) {
20→  const ip =
21→    request.headers.get("x-real-ip") ??
22→    request.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
23→    "anonymous";
24→  const { success, reset } = limiter.check(ip);
25→  if (!success) {
26→    return Response.json(
27→      { error: "Te veel verzoeken. Probeer het later opnieuw." },
28→      { status: 429, headers: { "Retry-After": String(Math.ceil((reset - Date.now()) / 1000)) } },
29→    );
30→  }
31→
32→  try {
33→    const body = await request.json().catch(() => ({}));
34→    const parsed = triggerSchema.safeParse(body);
35→    if (!parsed.success) {
36→      return Response.json({ error: "Ongeldige invoer" }, { status: 400 });
37→    }
38→
39→    // Load configs from DB
40→    let configs: (typeof scraperConfigs.$inferSelect)[];
41→    if (parsed.data.platform) {
42→      configs = await db
43→        .select()
44→        .from(scraperConfigs)
45→        .where(
46→          and(eq(scraperConfigs.platform, parsed.data.platform), eq(scraperConfigs.isActive, true)),
47→        )
48→        .limit(1);
49→    } else {
50→      configs = await db.select().from(scraperConfigs).where(eq(scraperConfigs.isActive, true));
51→    }
52→
53→    if (configs.length === 0) {
54→      return Response.json(
55→        { error: "Geen actieve scraper configuratie gevonden" },
56→        { status: 404 },
57→      );
58→    }
59→
60→    // Run pipelines via Promise.allSettled (non-blocking)
61→    const results = await Promise.allSettled(
62→      configs.map((cfg) => runScrapePipeline(cfg.platform, cfg.baseUrl)),
63→    );
64→
65→    const summary = configs.map((cfg, i) => {
66→      const r = results[i];
67→      return {
68→        platform: cfg.platform,
69→        status: r.status === "fulfilled" ? "success" : "failed",
70→        ...(r.status === "fulfilled" ? r.value : { error: String(r.reason) }),
71→      };
72→    });
73→
74→    revalidatePath("/opdrachten");
75→    revalidatePath("/scraper");
76→    revalidatePath("/overzicht");
77→    publish("scrape:completed", { platforms: summary.map((s) => s.platform) });
78→
79→    return Response.json({
80→      message: `Scrape gestart voor ${configs.length} platform(en)`,
81→      platforms: summary,
82→    });
83→  } catch (_err) {
84→    return Response.json({ error: "Interne serverfout" }, { status: 500 });
85→  }
86→}
