11→/** Converteer criteria naar recharts data: korte label + score 0–100 (stars*20 of pass 100). */
12→function toChartData(
13→  criteria: CriterionResult[],
14→): { name: string; score: number; fullName: string }[] {
15→  return criteria.map((c) => {
16→    const shortName = c.criterion.length > 20 ? `${c.criterion.slice(0, 18)}…` : c.criterion;
17→    let score = 50;
18→    if (c.tier === "knockout" && c.passed !== null) score = c.passed ? 100 : 0;
19→    else if (c.tier === "gunning" && c.stars !== null) score = c.stars * 20;
20→    return { name: shortName, score, fullName: c.criterion };
21→  });
22→}
