 21→type SkillCategory = "Technisch" | "Domeinkennis" | "Tools" | "Soft Skills" | "Talen";
 22→
 23→const TOOL_KEYWORDS = [
 24→  "jira",
 25→  "sap",
 26→  "excel",
 27→  "confluence",
 28→  "figma",
 29→  "docker",
