 87→  "swedish",
 88→  "norwegian",
 89→  "danish",
 90→  "finnish",
 91→  "nederlands",
 92→  "duits",
 93→  "frans",
 94→  "spaans",
 95→  "engels",
 96→];
 97→
 98→function classifyHardSkill(name: string): SkillCategory {
 99→  const lower = name.toLowerCase();
100→  if (LANGUAGE_KEYWORDS.some((kw) => lower.includes(kw))) return "Talen";
101→  if (TOOL_KEYWORDS.some((kw) => lower.includes(kw))) return "Tools";
102→  if (DOMAIN_KEYWORDS.some((kw) => lower.includes(kw))) return "Domeinkennis";
103→  return "Technisch";
104→}
105→
106→interface CategoryData {
107→  category: SkillCategory;
108→  value: number;
109→}
110→
111→function categorizeSkills(skills: StructuredSkills): CategoryData[] {
112→  const buckets: Record<SkillCategory, number[]> = {
113→    Technisch: [],
114→    Domeinkennis: [],
115→    Tools: [],
116→    "Soft Skills": [],
117→    Talen: [],
118→  };
119→
120→  for (const skill of skills.hard) {
121→    const cat = classifyHardSkill(skill.name);
122→    buckets[cat].push(skill.proficiency);
123→  }
124→
125→  for (const skill of skills.soft) {
126→    buckets["Soft Skills"].push(skill.proficiency);
127→  }
128→
129→  // Only include categories that have skills
130→  return Object.entries(buckets)
131→    .filter(([, values]) => values.length > 0)
132→    .map(([category, values]) => ({
133→      category: category as SkillCategory,
134→      value: values.reduce((sum, v) => sum + v, 0) / values.length,
135→    }));
136→}
137→
138→function FallbackBarChart({
139→  categories,
140→  compareCategories,
141→}: {
142→  categories: CategoryData[];
143→  compareCategories?: CategoryData[];
144→}) {
145→  return (
146→    <div className="space-y-3">
147→      {categories.map((cat) => {
148→        const compareCat = compareCategories?.find((c) => c.category === cat.category);
149→        return (
150→          <div key={cat.category}>
151→            <div className="flex justify-between text-sm mb-1">
152→              <span className="text-foreground">{cat.category}</span>
153→              <span className="text-muted-foreground">{cat.value.toFixed(1)}/5</span>
154→            </div>
155→            <div className="h-2 bg-muted rounded-full overflow-hidden">
156→              <div
157→                className="h-full bg-primary rounded-full"
158→                style={{ width: `${(cat.value / 5) * 100}%` }}
159→              />
160→            </div>
161→            {compareCat && (
162→              <div className="h-2 bg-muted rounded-full overflow-hidden mt-1">
163→                <div
164→                  className="h-full rounded-full"
165→                  style={{
166→                    width: `${(compareCat.value / 5) * 100}%`,
167→                    backgroundColor: "hsl(280, 68%, 60%)",
168→                  }}
169→                />
170→              </div>
171→            )}
172→          </div>
173→        );
174→      })}
175→    </div>
176→  );
177→}
178→
179→export function SkillsRadar({ skills, compareWith, className }: SkillsRadarProps) {
180→  const categories = categorizeSkills(skills);
181→  const compareCategories = compareWith ? categorizeSkills(compareWith) : undefined;
182→
183→  if (categories.length < 3) {
184→    return (
185→      <div className={cn("w-full", className)}>
186→        <FallbackBarChart categories={categories} compareCategories={compareCategories} />
187→      </div>
188→    );
189→  }
190→
191→  const data = categories.map((cat) => {
192→    const compareCat = compareCategories?.find((c) => c.category === cat.category);
193→    return {
194→      category: cat.category,
195→      candidate: Math.round(cat.value * 10) / 10,
196→      ...(compareCat ? { vergelijking: Math.round(compareCat.value * 10) / 10 } : {}),
197→    };
198→  });
199→
200→  return (
201→    <div className={cn("w-full", className)}>
202→      <ResponsiveContainer width="100%" height={300}>
203→        <RadarChart data={data}>
204→          <PolarGrid stroke="hsl(220, 13%, 80%)" />
205→          <PolarAngleAxis dataKey="category" tick={{ fontSize: 12 }} />
206→          <PolarRadiusAxis angle={30} domain={[0, 5]} tick={{ fontSize: 10 }} />
