 1→import { eq, sql } from "drizzle-orm";
 2→import { db } from "../db";
 3→import { scrapeResults, scraperConfigs } from "../db/schema";
 4→import { publish } from "../lib/event-bus";
 5→import { CIRCUIT_BREAKER_THRESHOLD } from "../lib/helpers";
 6→
 7→export async function recordScrapeResult(data: {
 8→  platform: string;
 9→  jobsFound: number;
10→  jobsNew: number;
11→  duplicates: number;
12→  durationMs: number;
13→  status: string;
14→  errors: string[];
15→}): Promise<void> {
16→  // Stap 1: Zoek config ID voor dit platform
17→  const configs = await db
18→    .select({
19→      id: scraperConfigs.id,
20→      consecutiveFailures: scraperConfigs.consecutiveFailures,
21→    })
22→    .from(scraperConfigs)
23→    .where(eq(scraperConfigs.platform, data.platform))
24→    .limit(1);
25→
26→  const configId = configs[0]?.id ?? null;
27→  const previousFailures = configs[0]?.consecutiveFailures ?? 0;
28→
29→  // Stap 2: Schrijf scrape resultaat (zonder costCredits/provider — niet in schema)
30→  await db.insert(scrapeResults).values({
31→    configId,
32→    platform: data.platform,
33→    durationMs: data.durationMs,
34→    jobsFound: data.jobsFound,
35→    jobsNew: data.jobsNew,
36→    duplicates: data.duplicates,
37→    status: data.status,
38→    errors: data.errors,
39→  });
40→
41→  // Stap 3: Update config lastRunAt + lastRunStatus + circuit breaker
42→  if (configId) {
43→    const isFailed = data.status === "failed";
44→    await db
45→      .update(scraperConfigs)
46→      .set({
47→        lastRunAt: new Date(),
48→        lastRunStatus: data.status,
49→        consecutiveFailures: isFailed ? sql`${scraperConfigs.consecutiveFailures} + 1` : 0,
50→        updatedAt: new Date(),
51→      })
52→      .where(eq(scraperConfigs.id, configId));
53→
54→    const currentFailures = isFailed ? previousFailures + 1 : 0;
55→    if (
56→      isFailed &&
57→      previousFailures < CIRCUIT_BREAKER_THRESHOLD &&
58→      currentFailures >= CIRCUIT_BREAKER_THRESHOLD
59→    ) {
60→      console.warn(
61→        `[Circuit Breaker] OPEN for ${data.platform} — ${currentFailures} consecutive failures (threshold: ${CIRCUIT_BREAKER_THRESHOLD})`,
62→      );
63→      publish("scrape:circuit_breaker_open", {
64→        platform: data.platform,
65→        previousFailures,
66→        currentFailures,
67→        threshold: CIRCUIT_BREAKER_THRESHOLD,
68→      });
69→    }
70→    if (!isFailed && previousFailures >= CIRCUIT_BREAKER_THRESHOLD) {
71→      console.info(
72→        `[Circuit Breaker] CLOSED for ${data.platform} — recovered after ${previousFailures} failures`,
73→      );
74→      publish("scrape:circuit_breaker_closed", {
75→        platform: data.platform,
76→        previousFailures,
77→      });
78→    }
79→  }
80→}
