import { desc, eq, sql } from "drizzle-orm";
import { db } from "../db";
import { jobs, scrapeResults } from "../db/schema";

// ========== Types ==========

export type ScrapeResult = typeof scrapeResults.$inferSelect;

export type GetHistoryOptions = {
  platform?: string;
  limit?: number;
};

export type PlatformStats = {
  platform: string;
  totalRuns: number;
  successCount: number;
  failedCount: number;
  successRate: number;
  totalJobsFound: number;
  totalJobsNew: number;
  totalDuplicates: number;
  avgDurationMs: number;
};

export type ScrapeAnalytics = {
  totalRuns: number;
  totalJobsFound: number;
  totalJobsNew: number;
  totalDuplicates: number;
  totalUniqueJobs: number;
  overallSuccessRate: number;
  avgDurationMs: number;
  byPlatform: PlatformStats[];
};

// ========== Service Functions ==========

/** Scrape resultaten ophalen, optioneel gefilterd op platform en gelimiteerd */
export async function getHistory(opts: GetHistoryOptions = {}): Promise<ScrapeResult[]> {
  const limit = Math.min(opts.limit ?? 50, 100);

  const baseQuery = db.select().from(scrapeResults);
  const filtered = opts.platform
    ? baseQuery.where(eq(scrapeResults.platform, opts.platform))
    : baseQuery;

  return filtered.orderBy(desc(scrapeResults.runAt)).limit(limit);
}

/** Bereken analytics per platform over alle scrape resultaten */
export async function getAnalytics(): Promise<ScrapeAnalytics> {
  // Single query: platform aggregation + unique jobs count via subquery
  const rows = await db
    .select({
      platform: scrapeResults.platform,
      totalRuns: sql<number>`count(*)::int`,
      successCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'success')::int`,
      failedCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'failed')::int`,
      totalJobsFound: sql<number>`coalesce(sum(${scrapeResults.jobsFound}), 0)::int`,
      totalJobsNew: sql<number>`coalesce(sum(${scrapeResults.jobsNew}), 0)::int`,
      totalDuplicates: sql<number>`coalesce(sum(${scrapeResults.duplicates}), 0)::int`,
      avgDurationMs: sql<number>`coalesce(avg(${scrapeResults.durationMs}), 0)::int`,
      totalUniqueJobs: sql<number>`(select count(*)::int from ${jobs} where ${jobs.deletedAt} is null)`,
    })
    .from(scrapeResults)
    .groupBy(scrapeResults.platform);

  // Extract unique jobs count from first row (subquery returns same value for all rows)
  const totalUniqueJobs = rows[0]?.totalUniqueJobs ?? 0;

  const byPlatform: PlatformStats[] = rows.map(({ totalUniqueJobs: _, ...r }) => ({
    ...r,
    successRate: r.totalRuns > 0 ? Math.round((r.successCount / r.totalRuns) * 100) : 0,
  }));

  const totalRuns = byPlatform.reduce((s, p) => s + p.totalRuns, 0);
  const totalSuccess = byPlatform.reduce((s, p) => s + p.successCount, 0);

  return {
    totalRuns,
    totalJobsFound: byPlatform.reduce((s, p) => s + p.totalJobsFound, 0),
    totalJobsNew: byPlatform.reduce((s, p) => s + p.totalJobsNew, 0),
    totalDuplicates: byPlatform.reduce((s, p) => s + p.totalDuplicates, 0),
    totalUniqueJobs,
    overallSuccessRate: totalRuns > 0 ? Math.round((totalSuccess / totalRuns) * 100) : 0,
    avgDurationMs:
      byPlatform.length > 0
        ? Math.round(byPlatform.reduce((s, p) => s + p.avgDurationMs, 0) / byPlatform.length)
        : 0,
    byPlatform,
  };
}

import { desc } from "drizzle-orm";
import {
  Activity,
  AlertTriangle,
  CheckCircle,
  Clock,
  Database,
  Search,
  Sparkles,
  XCircle,
} from "lucide-react";
import { PageHeader } from "@/components/page-header";
import { KPICard } from "@/components/shared/kpi-card";
import { StatusBadge } from "@/components/status-badge";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { db } from "@/src/db";
import { scrapeResults, scraperConfigs } from "@/src/db/schema";
import { getAnalytics } from "@/src/services/scrape-results";
import { ScraperActions } from "./actions";

export const dynamic = "force-dynamic";

export default async function ScraperPage() {
  const [configs, results, analytics] = await Promise.all([
    db.select().from(scraperConfigs).orderBy(scraperConfigs.platform),
    db.select().from(scrapeResults).orderBy(desc(scrapeResults.runAt)).limit(30),
    getAnalytics(),
  ]);

  return (
    <div className="flex-1 overflow-y-auto">
      <div className="max-w-[1400px] mx-auto px-4 md:px-6 lg:px-8 py-6 space-y-6">
        <PageHeader
          title="Scraper-dashboard"
          description="Beheer scraper configuraties en bekijk resultaten"
        >
          <ScraperActions />
        </PageHeader>

        {/* KPI Summary */}
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
          <KPICard
            icon={<Activity className="h-4 w-4" />}
            label="Totaal Runs"
            value={analytics.totalRuns}
            iconClassName="text-primary/60"
            valueClassName="text-primary"
            compact
          />
          <KPICard
            icon={<Search className="h-4 w-4" />}
            label="Actieve Vacatures"
            value={analytics.totalUniqueJobs}
            iconClassName="text-blue-500/60"
            valueClassName="text-blue-500"
            compact
          />
          <KPICard
            icon={<Sparkles className="h-4 w-4" />}
            label="Nieuw Toegevoegd"
            value={analytics.totalJobsNew}
            iconClassName="text-green-500/60"
            valueClassName="text-green-500"
            compact
          />
          <KPICard
            icon={<Database className="h-4 w-4" />}
            label="Verwerkt per run"
            value={
              analytics.totalRuns > 0
                ? Math.round(
                    (analytics.totalJobsNew + analytics.totalDuplicates) / analytics.totalRuns,
                  )
                : 0
            }
            iconClassName="text-amber-500/60"
            valueClassName="text-amber-500"
            compact
          />
          <KPICard
            icon={<CheckCircle className="h-4 w-4" />}
            label="Slagingspercentage"
            value={`${analytics.overallSuccessRate}%`}
            iconClassName="text-emerald-500/60"
            valueClassName={
              analytics.overallSuccessRate >= 80
                ? "text-emerald-500"
                : analytics.overallSuccessRate >= 50
                  ? "text-amber-500"
                  : "text-red-500"
            }
            compact
          />
          <KPICard
            icon={<Clock className="h-4 w-4" />}
            label="Gem. Duur"
            value={
              analytics.avgDurationMs > 0 ? `${(analytics.avgDurationMs / 1000).toFixed(1)}s` : "-"
            }
            iconClassName="text-muted-foreground"
            compact
          />
        </div>

        {/* Per-Platform Analytics */}
        {analytics.byPlatform.length > 0 && (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {analytics.byPlatform.map((p) => {
              const config = configs.find((c) => c.platform === p.platform);
              const circuitOpen = (config?.consecutiveFailures ?? 0) >= 5;

              return (
                <Card key={p.platform} className="bg-card border-border">
                  <CardHeader className="pb-3">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-base capitalize flex items-center gap-2">
                        {p.platform}
                        {circuitOpen && (
                          <Badge
                            variant="outline"
                            className="bg-red-500/10 text-red-500 border-red-500/20 text-[10px]"
                          >
                            <AlertTriangle className="h-3 w-3 mr-1" />
                            Circuit Open
                          </Badge>
                        )}
                      </CardTitle>
                      <StatusBadge
                        status={
                          !config?.isActive
                            ? "inactief"
                            : circuitOpen
                              ? "kritiek"
                              : (config?.consecutiveFailures ?? 0) > 0
                                ? "waarschuwing"
                                : "gezond"
                        }
                      />
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-3">
                    {/* Success rate bar */}
                    <div>
                      <div className="flex justify-between text-xs text-muted-foreground mb-1">
                        <span>Slagingspercentage</span>
                        <span
                          className={
                            p.successRate >= 80
                              ? "text-emerald-500"
                              : p.successRate >= 50
                                ? "text-amber-500"
                                : "text-red-500"
                          }
                        >
                          {p.successRate}%
                        </span>
                      </div>
                      <Progress value={p.successRate} className="h-1.5" />
                    </div>

                    {/* Stats grid */}
                    <div className="grid grid-cols-3 gap-2 text-center">
                      <div>
                        <p className="text-lg font-bold text-foreground">{p.totalJobsNew}</p>
                        <p className="text-[10px] text-muted-foreground">Nieuw</p>
                      </div>
                      <div>
                        <p className="text-lg font-bold text-foreground">{p.totalJobsFound}</p>
                        <p className="text-[10px] text-muted-foreground">Gevonden</p>
                      </div>
                      <div>
                        <p className="text-lg font-bold text-foreground">{p.totalRuns}</p>
                        <p className="text-[10px] text-muted-foreground">Runs</p>
                      </div>
                    </div>

                    {/* Run breakdown */}
                    <div className="flex items-center gap-2 text-xs text-muted-foreground pt-2 border-t border-border">
                      <span className="flex items-center gap-1">
                        <CheckCircle className="h-3 w-3 text-emerald-500" />
                        {p.successCount}
                      </span>
                      <span className="flex items-center gap-1">
                        <XCircle className="h-3 w-3 text-red-500" />
                        {p.failedCount}
                      </span>
                      <span className="ml-auto">
                        Gem. {p.avgDurationMs > 0 ? `${(p.avgDurationMs / 1000).toFixed(1)}s` : "-"}
                      </span>
                    </div>

                    {/* Config info */}
                    {config && (
                      <div className="text-xs text-muted-foreground space-y-0.5">
                        <p className="font-mono text-[10px] truncate">{config.baseUrl}</p>
                        {config.lastRunAt && (
                          <p>
                            Laatste:{" "}
                            {new Date(config.lastRunAt).toLocaleString("nl-NL", {
                              day: "numeric",
                              month: "short",
                              hour: "2-digit",
                              minute: "2-digit",
                            })}
                          </p>
                        )}
                      </div>
                    )}
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}

        {/* Configs without analytics data (newly added scrapers) */}
        {configs.filter((c) => !analytics.byPlatform.some((p) => p.platform === c.platform))
          .length > 0 && (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {configs
