                        </TableCell>
                        <TableCell className="text-right text-muted-foreground">
                          {result.durationMs ? `${(result.durationMs / 1000).toFixed(1)}s` : "-"}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

