import * as Sentry from "@sentry/nextjs";
import { rateLimit } from "./rate-limit";

type ApiHandler<TArgs extends unknown[]> = (...args: TArgs) => Response | Promise<Response>;

type ApiHandlerOptions = {
  errorMessage?: string;
  status?: number;
  logPrefix?: string;
  /** Rate limit config — omit to skip rate limiting */
  rateLimit?: { interval: number; limit: number };
};

// Pre-built rate limiters per tier to avoid creating new instances per request
const limiters = new Map<string, ReturnType<typeof rateLimit>>();

function getLimiter(key: string, interval: number, limit: number) {
  if (!limiters.has(key)) {
    limiters.set(key, rateLimit({ interval, limit }));
  }
  return limiters.get(key) ?? rateLimit({ interval, limit });
}

/** Extract client IP from request headers (works with Vercel, Cloudflare, etc.) */
function extractIp(request: Request): string {
  return (
    request.headers.get("x-real-ip") ??
    request.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
    "anonymous"
  );
}

export function withApiHandler<TArgs extends unknown[]>(
  handler: ApiHandler<TArgs>,
  options: ApiHandlerOptions = {},
) {
  const {
    errorMessage = "Interne serverfout",
    status = 500,
    logPrefix = "API handler error",
  } = options;

  const limiterKey = logPrefix; // Use log prefix as limiter identity

  return async (...args: TArgs): Promise<Response> => {
    // Rate limiting check (if configured)
    if (options.rateLimit) {
      const limiter = getLimiter(limiterKey, options.rateLimit.interval, options.rateLimit.limit);
      const request = args[0] as Request;
      const ip = extractIp(request);
      const { success, reset } = limiter.check(ip);
      if (!success) {
        return Response.json(
          { error: "Te veel verzoeken. Probeer het later opnieuw." },
          {
            status: 429,
            headers: { "Retry-After": String(Math.ceil((reset - Date.now()) / 1000)) },
          },
        );
      }
    }

    try {
      return await handler(...args);
    } catch (error) {
      console.error(`${logPrefix}:`, error);
      Sentry.captureException(error, { tags: { source: "api-handler" } });
      return Response.json({ error: errorMessage }, { status });
    }
  };
}

  }),
);

// ========== Scrape Resultaten ==========
export const scrapeResults = pgTable(
  "scrape_results",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    configId: uuid("config_id").references(() => scraperConfigs.id, {
      onDelete: "set null",
    }),
    platform: text("platform").notNull(),
    runAt: timestamp("run_at").defaultNow(),
    durationMs: integer("duration_ms"),
    jobsFound: integer("jobs_found").default(0),
    jobsNew: integer("jobs_new").default(0),
    duplicates: integer("duplicates").default(0),
    status: text("status").notNull(), // "success" | "partial" | "failed"
    errors: jsonb("errors").default([]),
  },
  (table) => ({
    configIdIdx: index("idx_scrape_results_config_id").on(table.configId),
    runAtIdx: index("idx_scrape_results_run_at").on(table.runAt),
    platformIdx: index("idx_scrape_results_platform").on(table.platform),
  }),
);

// ========== Opdrachten ==========
export const jobs = pgTable(
  "jobs",
  {
    id: uuid("id").primaryKey().defaultRandom(),

    // === Identificatie ===
    platform: text("platform").notNull(), // "striive", "indeed", "linkedin", "REDACTED", "flextender"
    externalId: text("external_id").notNull(), // Striive: referentiecode (bijv. "BTBDN000695")
    externalUrl: text("external_url"), // Volledige URL naar opdracht detail pagina
    clientReferenceCode: text("client_reference_code"), // Striive: referentiecode opdrachtgever

    // === Kern informatie ===

