+    parseDate(date)?.toLocaleDateString("nl-NL", {
+      day: "numeric",
+      month: "short",
+    }) ?? date
+  );
+}
+
+function aggregateByDate(data: TimeSeriesPoint[]) {
+  const aggregated = new Map<string, AggregatedPoint>();
+
+  for (const point of data) {
+    const current = aggregated.get(point.date) ?? {
+      date: point.date,
+      jobsFound: 0,
+      jobsNew: 0,
+      duplicates: 0,
+    };
